1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	function calculateQuotePremium(items: Array<{ type: string }>): number {
10	  const policyBasePremium = items.reduce(
11	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
12	    0
13	  );
14	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
15	  return policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE;
16	}
17	
18	export function processScenario(scenario: {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Array<{ op: string; items?: Array<{ type: string }> }>;
21	}): unknown {
22	  const results = scenario.steps.map((step) => {
23	    const premium = calculateQuotePremium(step.items ?? []);
24	    return { premium };
25	  });
26	  return { results };
27	}
